async function classifyChange(params) {
  // Simplified: only supports "advance" (append-only) which is what parent sessions do
  const { previous, current, sessionFile } = params;
  if (!previous?.fingerprint.exists || !current.exists) return;
  if (previous.fingerprint.dev !== current.dev || previous.fingerprint.ino !== current.ino) return;
  if (current.size <= previous.fingerprint.size) return;
  const appendedBytes = current.size - previous.fingerprint.size;
  if (appendedBytes > BigInt(MAX_BENIGN_SESSION_FENCE_ADVANCE_BYTES)) return;
  const length = Number(appendedBytes);
  const fd = await fs.open(sessionFile, 'r');
  try {
    const buffer = Buffer.alloc(length);
    const { bytesRead } = await fd.read(buffer, 0, length, Number(previous.fingerprint.size));
    if (bytesRead !== length) return;
    const text = buffer.toString('utf8');
    if (!text.endsWith('\n')) return;
    const lines = text.split('\n').filter(Boolean);
    // Each line must be a valid JSON message record
    const entries = [];
    const publishedEntries = [];
    for (const line of lines) {
      try {
        const parsed = JSON.parse(line);
        if (parsed.type !== 'message' || typeof parsed.id !== 'string') return; // hostile
