async function appendParentWrites(file, count, prefix) {
  const lines = [];
  for (let i = 0; i < count; i++) {
    lines.push(JSON.stringify({
      type: 'message', id: `${prefix}-${i}`, parentId: null,
      timestamp: new Date().toISOString(),
      message: { role: 'user', content: `${prefix} write ${i}` }
